// Mejora la tipografia del documento antes de convertirlo a Google Doc.
// Google Docs IGNORA el bloque <style>; solo respeta estilos inline en cada etiqueta.
// Por eso quitamos el <style> y aplicamos los estilos directamente en cada tag.
const SERIF = '"Times New Roman", serif';
const NAVY = '#1f3864';
const TEXT = '#1a1a1a';

return $input.all().map(item => {
  let html = item.json.doc_html || '';

  // Quitar el bloque <style> (causa del texto justificado en Arial)
  html = html.replace(/<style[\s\S]*?<\/style>/gi, '');

  // Encabezados: serif, azul marino, negrita
  html = html.replace(/<h1\b(?![^>]*\bstyle=)/gi, `<h1 style='font-family:${SERIF};font-size:20pt;font-weight:bold;color:${NAVY};margin-top:18pt;margin-bottom:8pt;'`);
  html = html.replace(/<h2\b(?![^>]*\bstyle=)/gi, `<h2 style='font-family:${SERIF};font-size:16pt;font-weight:bold;color:${NAVY};margin-top:16pt;margin-bottom:6pt;'`);
  html = html.replace(/<h3\b(?![^>]*\bstyle=)/gi, `<h3 style='font-family:${SERIF};font-size:13pt;font-weight:bold;color:${NAVY};margin-top:12pt;margin-bottom:4pt;'`);

  // Parrafos: serif, alineado a la izquierda, interlineado comodo
  html = html.replace(/<p\b(?![^>]*\bstyle=)/gi, `<p style='font-family:${SERIF};font-size:12pt;color:${TEXT};line-height:1.5;text-align:left;margin-bottom:10pt;'`);

  // Vinetas
  html = html.replace(/<li\b(?![^>]*\bstyle=)/gi, `<li style='font-family:${SERIF};font-size:12pt;color:${TEXT};line-height:1.5;text-align:left;margin-bottom:6pt;'`);

  // Negritas resaltadas en azul marino
  html = html.replace(/<strong\b(?![^>]*\bstyle=)/gi, `<strong style='font-family:${SERIF};color:${NAVY};'`);

  // Limitar el tamano de la imagen de la firma
  html = html.replace(/<img\b(?![^>]*\bstyle=)/gi, `<img style='height:90px;'`);

  return { json: { ...item.json, doc_html: html }, pairedItem: { item: 0 } };
});

// Calcula los grupos del alumno segun el tipo de contrato.
// Se guarda como texto separado por comas para la celda de seleccion multiple del Sheet.
const t = String($('trig_webhook_sign').first().json.body.tipo_contrato || '').toLowerCase().trim();

// Todos los alumnos pertenecen a Iniciacion
const grupos = ['Iniciación'];

// Advanced Healers: advanced healers, eca y energy master
if (['acuerdo_acceso_advanced_healers', 'alquimia_vital_eca', 'alquimia_vilal_eca', 'alquimia_vital_energy_master', 'alquimia_vilal_energy_master'].includes(t)) {
  grupos.push('Advanced Healers');
}

// Emprende con Alma: solo ECA
if (t === 'alquimia_vital_eca' || t === 'alquimia_vilal_eca') {
  grupos.push('Emprende con Alma');
}

// Energy Masters: solo energy master
if (t === 'alquimia_vital_energy_master' || t === 'alquimia_vilal_energy_master') {
  grupos.push('Energy Masters');
}

// oferta_iniciacion_vitaliza y resto: solo Iniciacion (ya incluido)

return [{ json: { tipo_contrato: t, grupos: grupos.join(', '), grupos_lista: grupos, plan: grupos[grupos.length - 1] }, pairedItem: { item: 0 } }];

